  it('computes mcp-env ref', () => {
    expect(refForDestination({
      kind: 'mcp-env', serverId: 'gh', envName: 'GH_TOKEN',
    })).toBe('mcp:gh:env:GH_TOKEN');
  });
  it('computes mcp-header ref', () => {
    expect(refForDestination({
      kind: 'mcp-header', serverId: 'gh', headerName: 'Authorization',
