710	
711	```ts
712	import type { AgentContext, HookBus } from '@ax/core';
713	
714	const MARKER_KEY = 'credentials:redesign-2026-05-19:wiped';
715	const CREDENTIAL_PREFIX = 'credential:'; // strict superset of v1 + v2
716	
717	/**
718	 * One-shot wipe of pre-redesign credential rows. Idempotent via a marker
719	 * key in `storage:set`. Safe to re-run; the second invocation reads the
720	 * marker and skips the delete.
721	 *
722	 * Pre-MVP / kind-dev only — see design §5.
723	 */
724	export async function wipePreRedesignCredentials(
725	  bus: HookBus,
726	  ctx: AgentContext,
727	): Promise<{ wiped: boolean; deleted: number }> {
728	  const marker = await bus.call<{ key: string }, { value: Uint8Array | undefined }>(
729	    'storage:get', ctx, { key: MARKER_KEY },
730	  );
731	  if (marker.value !== undefined && marker.value.length > 0) {
732	    return { wiped: false, deleted: 0 };
733	  }
734	  const { deleted } = await bus.call<
735	    { prefix: string },
736	    { deleted: number }
737	  >('storage:delete-prefix', ctx, { prefix: CREDENTIAL_PREFIX });
738	  await bus.call('storage:set', ctx, {
739	    key: MARKER_KEY,
740	    value: new TextEncoder().encode(new Date().toISOString()),
741	  });
742	  return { wiped: true, deleted };
743	}
744	```
