1316	import { makeAgentContext, type AgentContext, type HookBus } from '@ax/core';
1317	import { refForDestination, type Destination } from '@ax/credentials';
1318	import { z } from 'zod';
1319	import {
1320	  parseRequestBody, requireAdmin, requireUser, writeServiceError,
1321	  type RouteRequest, type RouteResponse,
1322	} from './shared.js';
1323	
1324	const PLUGIN_NAME = '@ax/credentials-admin-routes/destinations';
1325	
1326	const DestinationSchema = z.discriminatedUnion('kind', [
1327	  z.object({ kind: z.literal('provider'), provider: z.literal('anthropic') }).strict(),
1328	  z.object({ kind: z.literal('skill-slot'),
1329	             skillId: z.string().min(1).max(128),
1330	             slot: z.string().min(1).max(64) }).strict(),
1331	  z.object({ kind: z.literal('mcp-env'),
1332	             serverId: z.string().min(1).max(64),
1333	             envName: z.string().min(1).max(64) }).strict(),
1334	  z.object({ kind: z.literal('mcp-header'),
1335	             serverId: z.string().min(1).max(64),
1336	             headerName: z.string().min(1).max(128) }).strict(),
1337	  z.object({ kind: z.literal('routine-hmac'),
1338	             agentId: z.string().min(1).max(64),
1339	             routinePath: z.string().min(1).max(256) }).strict(),
1340	]);
1341	
1342	const CreateBody = z.object({
1343	  destination: DestinationSchema,
1344	  scope: z.enum(['global', 'user', 'agent']),
1345	  ownerId: z.string().min(1).max(128).nullable(),
1346	  kind: z.literal('api-key'),
1347	  payloadB64: z.string().min(1),
1348	}).strict();
1349	
1350	const DeleteBody = z.object({
1351	  destination: DestinationSchema,
1352	  scope: z.enum(['global', 'user', 'agent']),
1353	  ownerId: z.string().min(1).max(128).nullable(),
1354	}).strict();
1355	
1356	export function createDestinationHandlers(deps: { bus: HookBus }): {
1357	  create:        (req: RouteRequest, res: RouteResponse) => Promise<void>;
1358	  createSettings:(req: RouteRequest, res: RouteResponse) => Promise<void>;
1359	  destroy:       (req: RouteRequest, res: RouteResponse) => Promise<void>;
1360	  destroySettings:(req: RouteRequest, res: RouteResponse) => Promise<void>;
1361	} {
1362	  const ctx = makeAgentContext({
1363	    sessionId: 'credentials-destinations', agentId: PLUGIN_NAME, userId: 'system',
1364	  });
1365	
1366	  async function doCreate(req: RouteRequest, res: RouteResponse, forceUser: { userId: string } | null): Promise<void> {
1367	    const body = parseRequestBody(req, res, CreateBody);
1368	    if (body === null) return;
1369	    if (body.destination.kind !== req.params?.destinationKind) {
1370	      res.status(400).json({ error: 'destination.kind does not match route param' });
1371	      return;
1372	    }
1373	    const scope = forceUser !== null ? 'user' as const : body.scope;
1374	    const ownerId = forceUser !== null ? forceUser.userId : body.ownerId;
1375	    let ref: string;
1376	    try { ref = refForDestination(body.destination as Destination); }
1377	    catch (err) { if (writeServiceError(res, err)) return; throw err; }
1378	    try {
1379	      await deps.bus.call('credentials:set', ctx, {
1380	        scope, ownerId, ref, kind: body.kind,
1381	        payload: new Uint8Array(Buffer.from(body.payloadB64, 'base64')),
1382	      });
1383	      res.status(204).end();
1384	    } catch (err) { if (writeServiceError(res, err)) return; throw err; }
1385	  }
1386	
1387	  async function doDelete(req: RouteRequest, res: RouteResponse, forceUser: { userId: string } | null): Promise<void> {
1388	    const body = parseRequestBody(req, res, DeleteBody);
1389	    if (body === null) return;
1390	    if (body.destination.kind !== req.params?.destinationKind) {
1391	      res.status(400).json({ error: 'destination.kind does not match route param' });
1392	      return;
1393	    }
1394	    const scope = forceUser !== null ? 'user' as const : body.scope;
1395	    const ownerId = forceUser !== null ? forceUser.userId : body.ownerId;
1396	    let ref: string;
1397	    try { ref = refForDestination(body.destination as Destination); }
1398	    catch (err) { if (writeServiceError(res, err)) return; throw err; }
1399	    try {
1400	      await deps.bus.call('credentials:delete', ctx, { scope, ownerId, ref });
1401	      res.status(204).end();
1402	    } catch (err) { if (writeServiceError(res, err)) return; throw err; }
1403	  }
1404	
1405	  return {
1406	    async create(req, res) {
1407	      const actor = await requireAdmin(deps.bus, ctx, req, res);
1408	      if (actor === null) return;
1409	      await doCreate(req, res, null);
1410	    },
1411	    async createSettings(req, res) {
1412	      const actor = await requireUser(deps.bus, ctx, req, res);
1413	      if (actor === null) return;
1414	      await doCreate(req, res, { userId: actor.userId });
1415	    },
1416	    async destroy(req, res) {
1417	      const actor = await requireAdmin(deps.bus, ctx, req, res);
1418	      if (actor === null) return;
1419	      await doDelete(req, res, null);
1420	    },
1421	    async destroySettings(req, res) {
1422	      const actor = await requireUser(deps.bus, ctx, req, res);
1423	      if (actor === null) return;
1424	      await doDelete(req, res, { userId: actor.userId });
1425	    },
1426	  };
1427	}
1428	
1429	export async function registerDestinationRoutes(
1430	  bus: HookBus, ctx: AgentContext,
1431	): Promise<Array<() => void>> {
1432	  const h = createDestinationHandlers({ bus });
1433	  const unregisters: Array<() => void> = [];
1434	  for (const [method, path, handler] of [
1435	    ['POST',   '/admin/destinations/:destinationKind/credential',    h.create],
1436	    ['DELETE', '/admin/destinations/:destinationKind/credential',    h.destroy],
1437	    ['POST',   '/settings/destinations/:destinationKind/credential', h.createSettings],
1438	    ['DELETE', '/settings/destinations/:destinationKind/credential', h.destroySettings],
1439	  ] as const) {
1440	    const out = await bus.call<
1441	      { method: 'POST' | 'DELETE'; path: string; handler: unknown },
1442	      { unregister: () => void }
1443	    >('http:register-route', ctx, { method, path, handler });
1444	    unregisters.push(out.unregister);
1445	  }
1446	  return unregisters;
1447	}
1448	```
