    body: JSON.stringify({
      destination: args.destination,
      scope: args.scope.scope,
      ownerId: args.scope.ownerId,
    }),
  });
  if (!res.ok && res.status !== 404) {
    throw new Error(`HTTP ${res.status}: ${await res.text()}`);
  }
}
